// Check if today is a market holiday
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const ist = new Date(now.getTime() + istOffset + now.getTimezoneOffset() * 60 * 1000);
const dateStr = ist.toISOString().split('T')[0];
// In production: query market_holidays table
// For now, pass through
return [{ json: { date: dateStr, is_holiday: false } }];

// Combine all global data sources with error handling
let globalIndices = {};
let claudeResponse = {};
let finnhubNews = [];

try { globalIndices = $('NSE Service: Global Indices').first().json; } catch (e) { globalIndices = { error: 'NSE service unavailable', details: e.message }; }
try { claudeResponse = $('Claude: Global Market Search').first().json; } catch (e) { claudeResponse = { content: [{ type: 'text', text: '{}' }], error: e.message }; }
try { finnhubNews = $('Finnhub: Market News').first().json; } catch (e) { finnhubNews = []; }

// Parse Claude's web search results
let globalCues = {};
try {
  const content = claudeResponse.content || [];
  const text = content.filter(c => c.type === 'text').map(c => c.text).join('');
  const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  globalCues = JSON.parse(clean);
} catch (e) {
  globalCues = { parse_error: e.message, raw: claudeResponse.content };
}

// Filter relevant Finnhub news (last 12 hours)
const twelveHoursAgo = Math.floor(Date.now() / 1000) - 12 * 3600;
const newsArray = Array.isArray(finnhubNews) ? finnhubNews : [];
const recentNews = newsArray.filter(n => n.datetime > twelveHoursAgo).slice(0, 10);

const combinedData = {
  global_indices: globalIndices,
  global_cues: globalCues,
  overnight_news: recentNews.map(n => ({
    headline: n.headline,
    source: n.source,
    url: n.url,
    summary: n.summary
  })),
  collected_at: new Date().toISOString()
};

return [{ json: { data: combinedData, date: $('Holiday Check').first().json.date } }];
